import { useState, useMemo, memo, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useProduct } from "../context/ProductContext";

const ProductRow = memo(({ product, index, categories, onEdit, onDelete }) => {
  return (
    <tr style={{
      ...styles.tr,
      backgroundColor: index % 2 === 0 ? "#fff" : "#f9fafb",
    }}>
      <td style={styles.td}>
        <img
          src={product.image}
          alt={product.title}
          style={styles.tableImg}
          onError={(e) => { e.target.src = "https://via.placeholder.com/48"; }}
        />
      </td>
      <td style={styles.td}>
        <p style={styles.productName}>{product.title}</p>
        <p style={styles.productId}>ID: {product.id}</p>
      </td>
      <td style={styles.td}>
        <span style={styles.catBadge}>
          {categories.find((c) => c.key === product.category)?.icon}{" "}
          {product.category}
        </span>
      </td>
      <td style={styles.td}>
        <span style={styles.priceText}>
          {Number(product.price).toLocaleString("vi-VN")}đ
        </span>
      </td>
      <td style={styles.td}>
        <span style={{
          ...styles.stockBadge,
          backgroundColor: product.stock < 20 ? "#fff5f5" : "#f0fff4",
          color: product.stock < 20 ? "#e53e3e" : "#276749",
        }}>
          {product.stock < 20 ? "⚠️ " : "✅ "}{product.stock}
        </span>
      </td>
      <td style={styles.td}>
        <span style={styles.reviewBadge}>⭐ {product.reviews.length}</span>
      </td>
      <td style={styles.td}>
        <div style={styles.actionBtns}>
          <button style={styles.editBtn} onClick={() => onEdit(product)}>
            ✏️ Sửa
          </button>
          <button style={styles.deleteBtn} onClick={() => onDelete(product)}>
            🗑️ Xóa
          </button>
        </div>
      </td>
    </tr>
  );
});

const CategoryCard = memo(({ cat, productCount, onEdit, onDelete }) => {
  return (
    <div style={styles.catCard}>
      <div style={styles.catCardTop}>
        <span style={styles.catCardIcon}>{cat.icon}</span>
        <div>
          <p style={styles.catCardLabel}>{cat.label}</p>
          <p style={styles.catCardKey}>/{cat.key}</p>
        </div>
      </div>
      <p style={styles.catCardCount}>{productCount} sản phẩm</p>
      <div style={styles.actionBtns}>
        <button style={styles.editBtn} onClick={() => onEdit(cat)}>✏️ Sửa</button>
        <button style={styles.deleteBtn} onClick={() => onDelete(cat)}>🗑️ Xóa</button>
      </div>
    </div>
  );
});

function Admin() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const {
    products, categories,
    addProduct, updateProduct, deleteProduct,
    addCategory, updateCategory, deleteCategory,
  } = useProduct();

  const [tab, setTab] = useState("dashboard");
  const [showProductModal, setShowProductModal] = useState(false);
  const [editProduct, setEditProduct] = useState(null);
  const [productForm, setProductForm] = useState({
    title: "", category: "", price: "", stock: "", image: "",
  });
  const [showCatModal, setShowCatModal] = useState(false);
  const [editCat, setEditCat] = useState(null);
  const [catForm, setCatForm] = useState({ key: "", label: "", icon: "" });
  const [searchProduct, setSearchProduct] = useState("");
  const [filterCategory, setFilterCategory] = useState("");
  const [confirmDelete, setConfirmDelete] = useState(null);

  const openAddProduct = useCallback(() => {
    setEditProduct(null);
    setProductForm({
      title: "",
      category: categories[0]?.key || "",
      price: "",
      stock: "",
      image: "",
    });
    setShowProductModal(true);
  }, [categories]);

  const openEditProduct = useCallback((product) => {
    setEditProduct(product);
    setProductForm({
      title: product.title,
      category: product.category,
      price: product.price,
      stock: product.stock,
      image: product.image,
    });
    setShowProductModal(true);
  }, []);

  const handleSaveProduct = useCallback(() => {
    if (!productForm.title || !productForm.price || !productForm.stock) {
      alert("Vui lòng điền đầy đủ thông tin!");
      return;
    }
    const data = {
      ...productForm,
      price: Number(productForm.price),
      stock: Number(productForm.stock),
    };
    if (editProduct) {
      updateProduct(editProduct.id, data);
    } else {
      addProduct(data);
    }
    setShowProductModal(false);
  }, [productForm, editProduct, updateProduct, addProduct]);

  const openAddCat = useCallback(() => {
    setEditCat(null);
    setCatForm({ key: "", label: "", icon: "" });
    setShowCatModal(true);
  }, []);

  const openEditCat = useCallback((cat) => {
    setEditCat(cat);
    setCatForm({ key: cat.key, label: cat.label, icon: cat.icon });
    setShowCatModal(true);
  }, []);

  const handleSaveCat = useCallback(() => {
    if (!catForm.key || !catForm.label) {
      alert("Vui lòng điền đầy đủ thông tin!");
      return;
    }
    if (editCat) {
      updateCategory(editCat.key, catForm);
    } else {
      if (categories.find((c) => c.key === catForm.key)) {
        alert("Mã danh mục đã tồn tại!");
        return;
      }
      addCategory(catForm);
    }
    setShowCatModal(false);
  }, [catForm, editCat, categories, updateCategory, addCategory]);

  const handleDeleteConfirmed = useCallback(() => {
    if (!confirmDelete) return;
    if (confirmDelete.type === "product") {
      deleteProduct(confirmDelete.data.id);
    } else {
      deleteCategory(confirmDelete.data.key);
    }
    setConfirmDelete(null);
  }, [confirmDelete, deleteProduct, deleteCategory]);

  const filteredProducts = useMemo(() => {
    return products.filter((p) => {
      const matchSearch = p.title.toLowerCase().includes(searchProduct.toLowerCase());
      const matchCat = filterCategory ? p.category === filterCategory : true;
      return matchSearch && matchCat;
    });
  }, [products, searchProduct, filterCategory]);

  const totalStock = useMemo(() =>
    products.reduce((s, p) => s + p.stock, 0), [products]);

  const lowStockItems = useMemo(() =>
    products.filter((p) => p.stock < 20), [products]);

  const catProductCount = useMemo(() => {
    const map = {};
    categories.forEach((c) => {
      map[c.key] = products.filter((p) => p.category === c.key).length;
    });
    return map;
  }, [categories, products]);

  if (!user) {
    return (
      <div style={styles.accessDenied}>
        <p style={{ fontSize: "48px" }}>🔒</p>
        <h2>Bạn cần đăng nhập để truy cập trang này</h2>
        <button style={styles.loginBtn} onClick={() => navigate("/login")}>
          Đăng nhập
        </button>
      </div>
    );
  }

  return (
    <div style={styles.page}>
      {/* Sidebar */}
      <div style={styles.sidebar}>
        <div style={styles.sidebarLogo}>
          <span style={{ fontSize: "28px" }}>🛒</span>
          <div>
            <p style={styles.sidebarTitle}>FoodMart</p>
            <p style={styles.sidebarSub}>Admin Panel</p>
          </div>
        </div>
        <nav style={styles.sidebarNav}>
          {[
            { key: "dashboard", icon: "📊", label: "Dashboard" },
            { key: "products", icon: "🏪", label: "Sản phẩm" },
            { key: "categories", icon: "📦", label: "Danh mục" },
          ].map((item) => (
            <button
              key={item.key}
              style={{
                ...styles.sidebarItem,
                ...(tab === item.key ? styles.sidebarItemActive : {}),
              }}
              onClick={() => setTab(item.key)}
            >
              <span style={{ fontSize: "18px" }}>{item.icon}</span>
              <span>{item.label}</span>
            </button>
          ))}
        </nav>
        <button style={styles.backBtn} onClick={() => navigate("/")}>
          ← Về trang chủ
        </button>
      </div>

      {/* Main */}
      <div style={styles.main}>
        <div style={styles.mainHeader}>
          <h1 style={styles.mainTitle}>
            {tab === "dashboard" && "📊 Dashboard"}
            {tab === "products" && "🏪 Quản lý Sản phẩm"}
            {tab === "categories" && "📦 Quản lý Danh mục"}
          </h1>
          <div style={styles.adminInfo}>
            <div style={styles.adminAvatar}>
              {user.name.charAt(0).toUpperCase()}
            </div>
            <span style={styles.adminName}>{user.name}</span>
          </div>
        </div>

        {/* DASHBOARD */}
        {tab === "dashboard" && (
          <div>
            <div style={styles.statsGrid}>
              {[
                { icon: "🏪", value: products.length, label: "Tổng sản phẩm", color: "#38a169" },
                { icon: "📦", value: categories.length, label: "Danh mục", color: "#3182ce" },
                { icon: "📋", value: totalStock.toLocaleString(), label: "Tổng tồn kho", color: "#d69e2e" },
                { icon: "⚠️", value: lowStockItems.length, label: "Sắp hết hàng", color: "#e53e3e" },
              ].map((stat, i) => (
                <div key={i} style={{ ...styles.statCard, borderLeft: `4px solid ${stat.color}` }}>
                  <p style={styles.statIcon}>{stat.icon}</p>
                  <p style={styles.statValue}>{stat.value}</p>
                  <p style={styles.statLabel}>{stat.label}</p>
                </div>
              ))}
            </div>

            {lowStockItems.length > 0 && (
              <div style={styles.warningBox}>
                <h3 style={styles.warningTitle}>⚠️ Sản phẩm sắp hết hàng</h3>
                <div style={styles.warningList}>
                  {lowStockItems.map((p) => (
                    <div key={p.id} style={styles.warningItem}>
                      <img
                        src={p.image}
                        alt={p.title}
                        style={styles.warningImg}
                        onError={(e) => { e.target.src = "https://via.placeholder.com/40"; }}
                      />
                      <span style={styles.warningName}>{p.title}</span>
                      <span style={styles.warningStock}>Còn {p.stock} sp</span>
                      <button
                        style={styles.editSmallBtn}
                        onClick={() => { setTab("products"); openEditProduct(p); }}
                      >
                        Sửa
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div style={styles.catSummary}>
              <h3 style={styles.catSummaryTitle}>📦 Thống kê theo danh mục</h3>
              <div style={styles.catSummaryGrid}>
                {categories.map((cat) => (
                  <div key={cat.key} style={styles.catSummaryCard}>
                    <span style={{ fontSize: "28px" }}>{cat.icon}</span>
                    <p style={styles.catSummaryLabel}>{cat.label}</p>
                    <p style={styles.catSummaryCount}>
                      {catProductCount[cat.key] || 0} sản phẩm
                    </p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* PRODUCTS */}
        {tab === "products" && (
          <div>
            <div style={styles.tableControls}>
              <input
                type="text"
                placeholder="🔍 Tìm kiếm sản phẩm..."
                value={searchProduct}
                onChange={(e) => setSearchProduct(e.target.value)}
                style={styles.tableSearch}
              />
              <select
                value={filterCategory}
                onChange={(e) => setFilterCategory(e.target.value)}
                style={styles.tableFilter}
              >
                <option value="">Tất cả danh mục</option>
                {categories.map((c) => (
                  <option key={c.key} value={c.key}>{c.icon} {c.label}</option>
                ))}
              </select>
              <span style={styles.tableCount}>{filteredProducts.length} sản phẩm</span>
              <button style={styles.addBtn} onClick={openAddProduct}>
                + Thêm sản phẩm
              </button>
            </div>

            <div style={styles.tableWrapper}>
              <table style={styles.table}>
                <thead>
                  <tr style={styles.thead}>
                    <th style={styles.th}>Ảnh</th>
                    <th style={styles.th}>Tên sản phẩm</th>
                    <th style={styles.th}>Danh mục</th>
                    <th style={styles.th}>Giá</th>
                    <th style={styles.th}>Tồn kho</th>
                    <th style={styles.th}>Đánh giá</th>
                    <th style={styles.th}>Thao tác</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredProducts.map((product, index) => (
                    <ProductRow
                      key={product.id}
                      product={product}
                      index={index}
                      categories={categories}
                      onEdit={openEditProduct}
                      onDelete={(p) => setConfirmDelete({ type: "product", data: p })}
                    />
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* CATEGORIES */}
        {tab === "categories" && (
          <div>
            <div style={styles.tableControls}>
              <span style={styles.tableCount}>{categories.length} danh mục</span>
              <button style={styles.addBtn} onClick={openAddCat}>
                + Thêm danh mục
              </button>
            </div>
            <div style={styles.catGrid}>
              {categories.map((cat) => (
                <CategoryCard
                  key={cat.key}
                  cat={cat}
                  productCount={catProductCount[cat.key] || 0}
                  onEdit={openEditCat}
                  onDelete={(c) => setConfirmDelete({ type: "category", data: c })}
                />
              ))}
            </div>
          </div>
        )}
      </div>

      {/* PRODUCT MODAL */}
      {showProductModal && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <h2 style={styles.modalTitle}>
              {editProduct ? "✏️ Sửa sản phẩm" : "➕ Thêm sản phẩm"}
            </h2>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>Tên sản phẩm *</label>
              <input
                style={styles.modalInput}
                placeholder="Nhập tên sản phẩm"
                value={productForm.title}
                onChange={(e) => setProductForm((f) => ({ ...f, title: e.target.value }))}
              />
            </div>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>Danh mục *</label>
              <select
                style={styles.modalInput}
                value={productForm.category}
                onChange={(e) => setProductForm((f) => ({ ...f, category: e.target.value }))}
              >
                {categories.map((c) => (
                  <option key={c.key} value={c.key}>{c.icon} {c.label}</option>
                ))}
              </select>
            </div>
            <div style={styles.modalRow}>
              <div style={{ ...styles.modalField, flex: 1 }}>
                <label style={styles.modalLabel}>Giá (đ) *</label>
                <input
                  style={styles.modalInput}
                  type="number"
                  placeholder="VD: 45000"
                  value={productForm.price}
                  onChange={(e) => setProductForm((f) => ({ ...f, price: e.target.value }))}
                />
              </div>
              <div style={{ ...styles.modalField, flex: 1 }}>
                <label style={styles.modalLabel}>Tồn kho *</label>
                <input
                  style={styles.modalInput}
                  type="number"
                  placeholder="VD: 100"
                  value={productForm.stock}
                  onChange={(e) => setProductForm((f) => ({ ...f, stock: e.target.value }))}
                />
              </div>
            </div>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>URL Hình ảnh</label>
              <input
                style={styles.modalInput}
                placeholder="https://images.unsplash.com/..."
                value={productForm.image}
                onChange={(e) => setProductForm((f) => ({ ...f, image: e.target.value }))}
              />
              {productForm.image && (
                <img
                  src={productForm.image}
                  alt="preview"
                  style={styles.imagePreview}
                  onError={(e) => { e.target.style.display = "none"; }}
                />
              )}
            </div>
            <div style={styles.modalActions}>
              <button style={styles.cancelBtn} onClick={() => setShowProductModal(false)}>
                Hủy
              </button>
              <button style={styles.saveBtn} onClick={handleSaveProduct}>
                {editProduct ? "💾 Cập nhật" : "➕ Thêm mới"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* CATEGORY MODAL */}
      {showCatModal && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <h2 style={styles.modalTitle}>
              {editCat ? "✏️ Sửa danh mục" : "➕ Thêm danh mục"}
            </h2>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>Mã danh mục * (không dấu, dùng dấu -)</label>
              <input
                style={{
                  ...styles.modalInput,
                  ...(editCat ? { backgroundColor: "#f7fafc", color: "#a0aec0" } : {}),
                }}
                placeholder="VD: do-uong"
                value={catForm.key}
                onChange={(e) => setCatForm((f) => ({
                  ...f,
                  key: e.target.value.toLowerCase().replace(/\s/g, "-"),
                }))}
                disabled={!!editCat}
              />
            </div>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>Tên danh mục *</label>
              <input
                style={styles.modalInput}
                placeholder="VD: Đồ Uống"
                value={catForm.label}
                onChange={(e) => setCatForm((f) => ({ ...f, label: e.target.value }))}
              />
            </div>
            <div style={styles.modalField}>
              <label style={styles.modalLabel}>Icon (emoji)</label>
              <input
                style={styles.modalInput}
                placeholder="VD: 🥤"
                value={catForm.icon}
                onChange={(e) => setCatForm((f) => ({ ...f, icon: e.target.value }))}
              />
              {catForm.icon && (
                <div style={styles.iconPreview}>
                  <span style={{ fontSize: "32px" }}>{catForm.icon}</span>
                  <span style={{ color: "#4a5568", marginLeft: "8px" }}>{catForm.label}</span>
                </div>
              )}
            </div>
            <div style={styles.modalActions}>
              <button style={styles.cancelBtn} onClick={() => setShowCatModal(false)}>
                Hủy
              </button>
              <button style={styles.saveBtn} onClick={handleSaveCat}>
                {editCat ? "💾 Cập nhật" : "➕ Thêm mới"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* CONFIRM DELETE */}
      {confirmDelete && (
        <div style={styles.overlay}>
          <div style={{ ...styles.modal, maxWidth: "400px" }}>
            <p style={{ fontSize: "48px", textAlign: "center" }}>🗑️</p>
            <h2 style={{ ...styles.modalTitle, textAlign: "center" }}>Xác nhận xóa</h2>
            <p style={styles.confirmText}>
              Bạn có chắc muốn xóa{" "}
              <strong>
                {confirmDelete.type === "product"
                  ? confirmDelete.data.title
                  : confirmDelete.data.label}
              </strong>?
            </p>
            <div style={styles.modalActions}>
              <button style={styles.cancelBtn} onClick={() => setConfirmDelete(null)}>
                Hủy
              </button>
              <button
                style={{ ...styles.saveBtn, backgroundColor: "#e53e3e" }}
                onClick={handleDeleteConfirmed}
              >
                🗑️ Xóa
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

